// ═══════════════════════════════════════════════════
// EDIT THIS SECTION — your context and preferences
// ═══════════════════════════════════════════════════

const MY_CONTEXT = {
  name: 'Saswati Gorai',
  role: 'Growth AI Strategist and Automation Specialist, Bangalore',
  goal: 'Land GTM Engineer / Growth Architect / Automation Specialist role. Target: $5,000/month',


  company: 'Building VysionAI — AI automation agency',
  active_projects: [
    'n8n self-hosted workflows on Hostinger VPS',
    'Voice agent demo (Mona) via Millis AI',
    'SaaS cost calculator on Bolt/Netlify',
    'Reddit ICP research agent',
    'LinkedIn intelligence system (this workflow)'
  ],
  tools: 'n8n, Make.com, Clay, Apollo, HubSpot, OpenRouter, Claude, Bolt, Netlify, Canva',
  interests: 'AI tools and use cases, GTM systems, PLG, outbound automation, lifecycle marketing, content systems, how companies hire GTM roles, SaaS trends, creator economy',
  use_digest_for: 'Interview language, spotting relevant tools, content ideas, finding potential clients or collaborators',
  background: '7 years Product Management at Axis Bank, MBA IIT Kharagpur, transitioned into growth marketing and AI automation'
};

// Days to look back — change this number freely
const DAYS_BACK = 7;

// Min relevancy score to include in digest (0 = include all)
const MIN_SCORE = 20;

// ═══════════════════════════════════════════════════
// DO NOT EDIT BELOW THIS LINE
// ═══════════════════════════════════════════════════

const cutoffDate = new Date();
cutoffDate.setDate(cutoffDate.getDate() - DAYS_BACK);

const allRows = $input.all();

const recent = allRows.filter(function(item) {
  const row = item.json;
  const dateField = row['posted_date '] || row.posted_date || row.scraped_at || '';
  if (!dateField) return false;
  try {
    const score = parseInt(row.relevancy_score || '0', 10);
    return new Date(dateField) >= cutoffDate && score >= MIN_SCORE;
  } catch(e) { return true; }
});

if (recent.length === 0) {
  return [{ json: { skip: true, reason: 'No posts in last ' + DAYS_BACK + ' days above score ' + MIN_SCORE, post_count: 0, prompt: '', post_ids: [] } }];
}

recent.sort(function(a, b) {
  return parseInt(b.json.relevancy_score || '0', 10) - parseInt(a.json.relevancy_score || '0', 10);
});

const blocks = recent.map(function(item, i) {
  const p = item.json;
  const creatorName = (p['creator_name '] || p.creator_name || '').trim();
  const postUrl = (p['post_url '] || p.post_url || '').trim();
  const postedDate = (p['posted_date '] || p.posted_date || '').substring(0, 10);
  const postText = (p['post_text '] || p.post_text || '').substring(0, 1500);
  const score = p.relevancy_score || '?';
  const reason = p.relevancy_reason || '';
  return 'POST ' + (i+1) + ' | Score: ' + score + ' | ' + creatorName + ' | ' + postedDate + '\nURL: ' + postUrl + '\nWhy relevant: ' + reason + '\n' + postText;
}).join('\n\n---\n\n');

const today = new Date().toLocaleDateString('en-IN', { day: 'numeric', month: 'long', year: 'numeric' });

const prompt = 'You are a personal intelligence assistant for ' + MY_CONTEXT.name + ', ' + MY_CONTEXT.role + '.\n\n' +
'CONTEXT:\n' +
'- Goal: ' + MY_CONTEXT.goal + '\n' +
'- Company: ' + MY_CONTEXT.company + '\n' +
'- Active projects: ' + MY_CONTEXT.active_projects.join(', ') + '\n' +
'- Tools: ' + MY_CONTEXT.tools + '\n' +
'- Interests: ' + MY_CONTEXT.interests + '\n' +
'- Uses this digest for: ' + MY_CONTEXT.use_digest_for + '\n\n' +
'Below are ' + recent.length + ' LinkedIn posts from the last ' + DAYS_BACK + ' days (score >= ' + MIN_SCORE + '), sorted by relevancy. Each post includes its URL — include the URL next to every insight you extract.\n\n' +
blocks + '\n\n---\n\n' +
'Write the digest in this exact format:\n\n' +
'NEW AI TOOLS & PRODUCTS\n' +
'Each: tool name | what it does | why relevant to Saswati | post URL\n\n' +
'GTM & GROWTH TRENDS\n' +
'Key insights on GTM, PLG, outbound, sales motion. Flag what she should mention in interviews. Include post URL for each point.\n\n' +
'HOW COMPANIES ARE RUNNING GTM\n' +
'Team structures, hiring signals, what is working right now. Include post URL for each point.\n\n' +
'AUTOMATION & WORKFLOW IDEAS\n' +
'Systems or workflows she could build as VysionAI offerings or portfolio pieces. Include post URL.\n\n' +
'INTERVIEW & OUTREACH LANGUAGE\n' +
'Exact phrases and frameworks she should use with recruiters and clients. Include post URL source.\n\n' +
'CONTENT IDEAS\n' +
'3-5 content angles based on what is trending in these posts. Include post URL for each angle.\n\n' +
'MUST-READ POSTS THIS ROUND\n' +
'Top 5 posts she should open and read fully. Format: creator name | one-line reason | URL\n\n' +
'Be direct and specific. Tie everything to her goals. Today: ' + today;

const postIds = recent.map(function(item) { return item.json.post_id; }).filter(Boolean);

return [{ json: { prompt: prompt, post_count: recent.length, post_ids: postIds, skip: false } }];

const ids = $('Context + Build Prompt — EDIT HERE').first().json.post_ids || [];
return ids.map(function(id) {
  return { json: { post_id: id, processed: 'true' } };
});
